import java.util.HashMap;

public boolean isGoodString(String s) {
    HashMap<Character, Integer> freq_map = new HashMap<>();
    for (char c : s.toCharArray()) {
        freq_map.put(c, freq_map.getOrDefault(c, 0) + 1);
    }

    int count = freq_map.values().iterator().next();
    for (int value : freq_map.values()) {
        if (value != count) {
            return false;
        }
    }
    return true;
}
```

